body:
@keyframes tagIn { 
  0% { opacity: 0; transform: translateY(4px); }
  100% { opacity: 1; transform: translateY(0px); }
}

@keyframes sparkRise { 
  0% { transform: scaleY(0.1); transform-origin: center bottom; }
  100% { transform: scaleY(1); transform-origin: center bottom; }
}

@keyframes baPulse { 
  0% { box-shadow: rgba(16, 207, 149, 0.45) 0px 0px 0px 0px; }
  70% { box-shadow: rgba(16, 207, 149, 0) 0px 0px 0px 8px; }
  100% { box-shadow: rgba(16, 207, 149, 0) 0px 0px 0px 0px; }
}
